package io.harbor.textd.core;

import java.lang.ref.PhantomReference;
import java.lang.ref.Reference;
import java.lang.ref.ReferenceQueue;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;

public final class GenerationRetirementWatch {
    private static final ReferenceQueue<ClassLoader> RETIRED = new ReferenceQueue<>();
    private static final Set<PhantomReference<ClassLoader>> ACTIVE = ConcurrentHashMap.newKeySet();

    private GenerationRetirementWatch() {
    }

    static void track(ClassLoader loader) {
        reap();
        ACTIVE.add(new PhantomReference<>(loader, RETIRED));
    }

    public static int activeCount() {
        reap();
        return ACTIVE.size();
    }

